import msgpack, os, glob, re
files = sorted(glob.glob('/home/claude-user/.cache/pip/http/**/*', recursive=True))
files = [f for f in files if os.path.isfile(f)]
results = []
for f in files:
    sz = os.path.getsize(f)
    name = '?'
    try:
        with open(f, 'rb') as fh:
            unpacker = msgpack.Unpacker(fh, raw=False, strict_map_key=False)
            data = next(iter(unpacker))
        # walk and find any string containing .whl or .tar.gz
        def walk(o):
            if isinstance(o, dict):
                for k, v in o.items():
                    yield from walk(k); yield from walk(v)
            elif isinstance(o, (list, tuple)):
                for x in o: yield from walk(x)
            elif isinstance(o, (bytes, str)):
                yield o
        for s in walk(data):
            if isinstance(s, bytes):
                try: s = s.decode('utf-8', 'ignore')
                except: continue
            m = re.search(r'([A-Za-z0-9_.+-]+\.(?:whl|tar\.gz|zip))', s)
            if m:
                name = m.group(1)
                break
    except Exception as e:
        name = f'ERR'
    results.append((sz, name))
results.sort(reverse=True)
for sz, n in results[:30]:
    print(f'{sz/1048576:7.1f} MB   {n}')
EOF
